changeSet.sql:
ALTER TABLE nexus.catalog_documents
    ADD COLUMN deleted_at TIMESTAMPTZ NULL;

ALTER TABLE nexus.catalog_links
    ADD COLUMN deleted_at TIMESTAMPTZ NULL;

CREATE INDEX idx_catalog_documents_collection_live
    ON nexus.catalog_documents (tenant_id, physical_collection)
    WHERE deleted_at IS NULL;

CREATE INDEX idx_catalog_documents_source_uri_live
    ON nexus.catalog_documents (tenant_id, source_uri)
    WHERE deleted_at IS NULL AND source_uri != '';

CREATE INDEX idx_catalog_links_from_live
    ON nexus.catalog_links (tenant_id, from_tumbler)
    WHERE deleted_at IS NULL;

CREATE INDEX idx_catalog_links_to_live
    ON nexus.catalog_links (tenant_id, to_tumbler)
    WHERE deleted_at IS NULL;

CREATE INDEX idx_catalog_links_from_type_live
    ON nexus.catalog_links (tenant_id, from_tumbler, link_type)
    WHERE deleted_at IS NULL;

CREATE INDEX idx_catalog_links_to_type_live
    ON nexus.catalog_links (tenant_id, to_tumbler, link_type)
    WHERE deleted_at IS NULL;

rollback.sql:
DROP INDEX IF EXISTS nexus.idx_catalog_links_to_type_live;
DROP INDEX IF EXISTS nexus.idx_catalog_links_from_type_live;
DROP INDEX IF EXISTS nexus.idx_catalog_links_to_live;
DROP INDEX IF EXISTS nexus.idx_catalog_links_from_live;
DROP INDEX IF EXISTS nexus.idx_catalog_documents_source_uri_live;
DROP INDEX IF EXISTS nexus.idx_catalog_documents_collection_live;

changeSet.sql:
CREATE OR REPLACE FUNCTION nexus.purge_trash(older_than interval) RETURNS bigint LANGUAGE plpgsql SECURITY INVOKER AS $$ DECLARE v_tenant TEXT; v_count BIGINT; BEGIN -- GUC guard: must have a non-empty tenant scope v_tenant := current_setting('nexus.tenant', true); IF v_tenant IS NULL OR v_tenant = '' THEN RAISE EXCEPTION 'purge_trash: nexus.tenant GUC must be set to a non-empty tenant scope. ' 'Cross-tenant purge is not permitted. Set the nexus.tenant configuration ' 'parameter before calling purge_trash.'; END IF;
-- Step 1: sweep orphaned chunk rows from chunks_384. -- A chunk (tenant_id, collection, chash) is orphaned when NO live manifest row -- (catalog_document_chunks joined to catalog_documents WHERE deleted_at IS NULL) -- references it for the same tenant. DELETE FROM nexus.chunks_384 c WHERE c.tenant_id = v_tenant AND NOT EXISTS ( SELECT 1 FROM nexus.catalog_document_chunks m JOIN nexus.catalog_documents d ON d.tenant_id = m.tenant_id AND d.tumbler = m.doc_id WHERE m.tenant_id = c.tenant_id AND m.chash = c.chash AND d.deleted_at IS NULL );
-- Step 2: sweep orphaned chunk rows from chunks_768. DELETE FROM nexus.chunks_768 c WHERE c.tenant_id = v_tenant AND NOT EXISTS ( SELECT 1 FROM nexus.catalog_document_chunks m JOIN nexus.catalog_documents d ON d.tenant_id = m.tenant_id AND d.tumbler = m.doc_id WHERE m.tenant_id = c.tenant_id AND m.chash = c.chash AND d.deleted_at IS NULL );
-- Step 3: sweep orphaned chunk rows from chunks_1024. DELETE FROM nexus.chunks_1024 c WHERE c.tenant_id = v_tenant AND NOT EXISTS ( SELECT 1 FROM nexus.catalog_document_chunks m JOIN nexus.catalog_documents d ON d.tenant_id = m.tenant_id AND d.tumbler = m.doc_id WHERE m.tenant_id = c.tenant_id AND m.chash = c.chash AND d.deleted_at IS NULL );
-- Step 4: physically delete tombstoned documents older than the threshold. -- fk-001 ON DELETE CASCADE removes catalog_document_chunks, document_aspects, -- document_highlights, and aspect_extraction_queue rows for each deleted doc. DELETE FROM nexus.catalog_documents WHERE tenant_id = v_tenant AND deleted_at IS NOT NULL AND deleted_at <= NOW() - older_than;
GET DIAGNOSTICS v_count = ROW_COUNT; RETURN v_count; END; $$

GRANT EXECUTE ON FUNCTION nexus.document_trash(text)    TO nexus_svc;
GRANT EXECUTE ON FUNCTION nexus.document_restore(text)  TO nexus_svc;
GRANT EXECUTE ON FUNCTION nexus.purge_trash(interval)   TO nexus_svc;
GRANT SELECT ON nexus.live_chunks                        TO PUBLIC;

rollback.sql:
REVOKE SELECT ON nexus.live_chunks                       FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION nexus.purge_trash(interval)  FROM nexus_svc;
REVOKE EXECUTE ON FUNCTION nexus.document_restore(text) FROM nexus_svc;
REVOKE EXECUTE ON FUNCTION nexus.document_trash(text)   FROM nexus_svc;
